package ra.edu.shoesphere.controller;
import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import ra.edu.shoesphere.model.dto.request.CreateOrderRequestDTO; import ra.edu.shoesphere.model.dto.response.ApiDataResponse; import ra.edu.shoesphere.model.entity.Order; import ra.edu.shoesphere.service.OrderService;
@RestController @RequestMapping("/api/v1/orders") @RequiredArgsConstructor public class OrderController { private final OrderService service; @PostMapping public ResponseEntity<ApiDataResponse<Order>> create(Authentication a,@Valid @RequestBody CreateOrderRequestDTO r){return ResponseEntity.status(HttpStatus.CREATED).body(new ApiDataResponse<>(true,"Order created.",service.create(a.getName(),r),null,HttpStatus.CREATED));} }
